const departments = [
  "ATTA", "BAKERY", "CHUTNEY/PICKLES/PASTES/PULP", "COCONUT/COCONUT CREAM", 
  "COSMETICS", "Customer Payments", "DAIRY", "DISPOSABELS", "DIWALI", 
  "DRINK-MIX/SYRUPS/TEA", "DRY FRUIT/NUTS", "DRY SNACKS/CHIPS/NAMKEEN", 
  "FISH/MEAT", "FLOUR", "FRESH SUPPLIES", "FROZEN", "GHEE", "GIFT VOUCHERS", 
  "HERBALS", "HOME CARE", "INSTANT MIX/READY TO COOK", "KITCHEN EXPENDITURE", 
  "LENTILS", "LOLLIES/CANDIES/CHOCOLATES", "MILLETS", "MOBILE PLANS/RECHARGE", 
  "MUKHWAS", "NOODLES", "OIL", "OTHERS", "PARTY PACKS", "POS Payment Surcharges", 
  "PROMO ITEMS", "READY TO EAT", "RELIGIOUS/POOJA ITEMS", "RICE", 
  "SOFT DRINKS/JUICES/LASSI", "SPICES", "SWEETS", "UNKNOWN"
];

// This formats the list so n8n processes each department as a separate item
return departments.map(dept => {
  return {
    json: { department_name: "SWEETS" }
  };
});

// Use the $ prefix for the helper function
const data = $getWorkflowStaticData('global');

// Initialize counter if missing
if (data.departmentCounter === undefined) {
  data.departmentCounter = 0;
}

// Increment counter
data.departmentCounter += 1;

return [
  {
    counter: data.departmentCounter,
    shouldWait: data.departmentCounter % 50 === 0
  }
];
